import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as c}from"./nyalra_no_mono-8344e451.js";import{_ as p,W as s,X as _,Y as i,Z as e,$ as t,a1 as o,a2 as m,a0 as d,C as a}from"./framework-91490e6a.js";const b={},f=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),g={href:"https://tree-novel.com/works/episode/6250cbb20b482ed7ae55e57eb646f233.html",target:"_blank",rel:"noopener noreferrer"},h=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),k=d('<hr><p>我每天都在互联网上发布日记。已经三年了。我发布的日记数量已经接近1000篇。如果文思泉涌，就会写得更长，但大致上平均每天1500字左右。虽然也取决于内容情况，但通常会花费大约一个小时。有时，会因为不知道写什么而苦思冥想2到3个小时。虽然想早点睡觉，但在无法发布日记的苦闷中挣扎是非常痛苦的。这已经成为一种苦行。</p><p>然而，正因为是苦行，才能收获一些东西。具体来说是读者和自信。坚持下去后，反响会越来越多，会有很多人给予反馈，表达共鸣，甚至让我感动。用自己写的文字触动别人的内心。没有比这更让人高兴的事情了。尽管如此，我并不是为了别人而做这些，所以我觉得主要还是自信的部分更重要。</p><p>没错，自信。也可以称之为自我肯定感。在这个每天都有出色的人创作出出色作品的可怕现代社会中，能够确立自己有独特魅力的身份是多么幸运。一不留神，你可能会被信息的洪流冲走。但能够稳固站在原地，自信地面对这一切的人，真的很了不起。</p><p>哎呀，持续数年撰写文章，无论是谁都会变得更加娴熟。</p><p>这样构建句子会更加有味道，增加紧张感，带来意外性，吸引他人的兴趣……尤其是我经常写关于当天欣赏的作品的感想或介绍，所以我非常注重表达我热爱的作品有多么精彩。没有理由，但这确实很有趣，很令人愉快。当我喜欢的作品也受到其他人的喜欢时，那一刻真的很让人高兴。</p><p>有时甚至会错觉地认为「自己是为此而活的」。实际上，除了每天的日记之外，我还会发布“我的当月最佳音乐和书籍”。我已经坚持这么做了好几年。这太有趣了...它成为了激励我投身新事物的动力，好事。这是我坚信的少数几个「自我」之一。我最闪耀的时刻就是谈论我热爱的作品的时刻。</p><p>如果你认为被愚弄了，那就试试写日记吧。当然，每天会牺牲一个小时。此外，你不会从中赚到钱。你得到的只是对自己写作能力的自信，而这是金钱买不到的。</p><p>这是一种修行。每天都在与手机和键盘打交道，花费一个小时来面对自己，这是一种神秘的时间。在现代，进行修行是多么低效！这个时代实在是不必为了这种毫无意义的事情而努力生活！而且，社交媒体上有无数由他人编写的文章！</p><p>正因如此，正因如此。在这个充满「意义」和「现实」的世界中，度过毫无意义的时间，面对自己。从某种意义上说，这是最奢侈的时间利用方式。在今天，年轻人都以2倍速观看视频，时间性价比成为流行概念。这就是它的意义。你的自尊心就在其中。</p><p>阅读这篇文章的人中，可能有10%会尝试动手写日记。在其中，坚持写数年的人可能只占0.01%。但如果你能成为这微小数字中的一员，你将能够自信地走在街头，肩并肩感受风的吹拂。这个城市的居民中没有人能持续数年发布日记。在这个领域，你绝对是主角！</p><hr><p><img src="'+c+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/f6fc2ff666d41fc9a86189d6d4321aab.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/0f77797a5b064b3cbccbde94b57cbb69.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/ea4c94b325e2bb833cdb3af5677ce8be.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【书架】我的书架。我决定一次性展示而不是详细刻画。因为我是个男人。在这个时代，我仍然选择用纸保存的，都是我精挑细选的收藏品。</p></blockquote>',14);function u(y,x){const l=a("ExternalLinkIcon"),n=a("RouterLink");return s(),_("div",null,[i(" more "),f,e("p",null,[t("原文链接："),e("a",g,[t("第23回／毎日一時間を犠牲にする覚悟"),o(l)])]),e("blockquote",null,[h,e("p",null,[o(n,{to:"/posts/Translate/nyalra_kb_22.html"},{default:m(()=>[t("【奈亚拉面壁自语】第22回｜VS“回声室现象”与“过滤泡现象”【230418】")]),_:1})])]),k])}const z=p(b,[["render",u],["__file","nyalra_kb_23.html.vue"]]);export{z as default};
